// Compute yesterday's date range in America/New_York timezone
const now = new Date();
const etOffsetMs = -5 * 60 * 60 * 1000; // EST baseline; n8n timezone setting handles DST display
const nowEt = new Date(now.getTime() + etOffsetMs);

const yesterdayEt = new Date(nowEt);
yesterdayEt.setUTCDate(nowEt.getUTCDate() - 1);
yesterdayEt.setUTCHours(0, 0, 0, 0);

const todayEt = new Date(yesterdayEt);
todayEt.setUTCDate(yesterdayEt.getUTCDate() + 1);

// Convert ET midnight back to UTC ISO
const startUtc = new Date(yesterdayEt.getTime() - etOffsetMs).toISOString();
const endUtc = new Date(todayEt.getTime() - etOffsetMs).toISOString();
const dateStr = yesterdayEt.toISOString().slice(0, 10);

// Stripe / Gumroad use unix timestamps
const startUnix = Math.floor(new Date(startUtc).getTime() / 1000);
const endUnix = Math.floor(new Date(endUtc).getTime() / 1000);

// 30-day rolling window for refund-rate calculation
const rollingStart = new Date(yesterdayEt);
rollingStart.setUTCDate(yesterdayEt.getUTCDate() - 29);
const rollingStartUtc = new Date(rollingStart.getTime() - etOffsetMs).toISOString();

return [{ json: {
  date: dateStr,
  start_utc: startUtc,
  end_utc: endUtc,
  start_unix: startUnix,
  end_unix: endUnix,
  rolling_start_utc: rollingStartUtc,
  generated_at: now.toISOString()
}}];

const range = $node['Compute Yesterday Range'].json;
const yesterday = $node['List Orders Yesterday'].all().map(i => i.json.fields || i.json);
const rolling = $node['List Orders Last 30 Days'].all().map(i => i.json.fields || i.json);

const sum = (arr, fn) => arr.reduce((acc, r) => acc + (fn(r) || 0), 0);
const count = (arr, pred) => arr.filter(pred).length;

const byPlatform = (plat) => yesterday.filter(o => (o['Platform'] || '').toLowerCase() === plat);

const revenue_total = sum(yesterday, o => Number(o['Gross amount']));
const revenue_etsy = sum(byPlatform('etsy'), o => Number(o['Gross amount']));
const revenue_gumroad = sum(byPlatform('gumroad'), o => Number(o['Gross amount']));
const revenue_is = sum(byPlatform('is'), o => Number(o['Gross amount']));
const orders_total = yesterday.length;
const orderbumps = count(yesterday, o => o['OrderBump taken?'] === true);
const otos = count(yesterday, o => o['OTO taken?'] === true);
const orderbump_rate = orders_total ? orderbumps / orders_total : 0;
const oto_rate = orders_total ? otos / orders_total : 0;

// Rolling 30-day refund rate
const refunded30 = count(rolling, o => (o['Refund status'] || '').toLowerCase() === 'full' || (o['Refund status'] || '').toLowerCase() === 'partial');
const refund_rate_rolling_30 = rolling.length ? refunded30 / rolling.length : 0;

// Top products yesterday
const productMap = {};
for (const o of yesterday) {
  const sku = Array.isArray(o['Product']) ? (o['Product'][0]?.name || o['Product'][0] || 'unknown') : (o['Product'] || 'unknown');
  const key = String(sku);
  if (!productMap[key]) productMap[key] = { sku: key, units: 0, revenue: 0 };
  productMap[key].units += 1;
  productMap[key].revenue += Number(o['Gross amount']) || 0;
}
const top_products = Object.values(productMap).sort((a, b) => b.revenue - a.revenue).slice(0, 5);

const summary = {
  date: range.date,
  revenue_total: Number(revenue_total.toFixed(2)),
  revenue_etsy: Number(revenue_etsy.toFixed(2)),
  revenue_gumroad: Number(revenue_gumroad.toFixed(2)),
  revenue_is: Number(revenue_is.toFixed(2)),
  orders_total,
  orderbump_rate: Number(orderbump_rate.toFixed(4)),
  oto_rate: Number(oto_rate.toFixed(4)),
  refund_rate_rolling_30: Number(refund_rate_rolling_30.toFixed(4)),
  top_products,
  start_unix: range.start_unix,
  end_unix: range.end_unix
};

// One row per metric_name for Airtable Metrics writes
const metricRows = [
  { date: range.date, metric_name: 'revenue_total', value: summary.revenue_total, summary },
  { date: range.date, metric_name: 'revenue_etsy', value: summary.revenue_etsy, summary },
  { date: range.date, metric_name: 'revenue_gumroad', value: summary.revenue_gumroad, summary },
  { date: range.date, metric_name: 'revenue_is', value: summary.revenue_is, summary },
  { date: range.date, metric_name: 'orders_total', value: summary.orders_total, summary },
  { date: range.date, metric_name: 'orderbump_rate', value: summary.orderbump_rate, summary },
  { date: range.date, metric_name: 'oto_rate', value: summary.oto_rate, summary },
  { date: range.date, metric_name: 'refund_rate_rolling_30', value: summary.refund_rate_rolling_30, summary },
  { date: range.date, metric_name: 'top_products', value: 0, summary, notes: JSON.stringify(summary.top_products) }
];

return metricRows.map(r => ({ json: r }));

const summary = $node['Aggregate Metrics'].first().json.summary;

const stripeData = $node['Stripe Balance Transactions'].first().json || {};
const stripeTxns = stripeData.data || [];
const stripeTotal = stripeTxns.reduce((acc, t) => acc + ((t.amount || 0) / 100), 0);

const gumroadData = $node['Gumroad Sales Yesterday'].first().json || {};
const gumroadSales = gumroadData.sales || [];
const gumroadTotal = gumroadSales.reduce((acc, s) => acc + (parseFloat(s.price) || 0), 0);

const pctDelta = (a, b) => {
  if (a === 0 && b === 0) return 0;
  if (a === 0) return 1;
  return Math.abs((a - b) / a);
};

const stripeDelta = pctDelta(summary.revenue_is, stripeTotal);
const gumroadDelta = pctDelta(summary.revenue_gumroad, gumroadTotal);

const discrepancies = [];
if (stripeDelta > 0.01) {
  discrepancies.push({
    platform: 'stripe',
    airtable: summary.revenue_is,
    api: Number(stripeTotal.toFixed(2)),
    delta_pct: Number((stripeDelta * 100).toFixed(2))
  });
}
if (gumroadDelta > 0.01) {
  discrepancies.push({
    platform: 'gumroad',
    airtable: summary.revenue_gumroad,
    api: Number(gumroadTotal.toFixed(2)),
    delta_pct: Number((gumroadDelta * 100).toFixed(2))
  });
}

return [{ json: {
  date: summary.date,
  summary,
  stripe_total: Number(stripeTotal.toFixed(2)),
  gumroad_total: Number(gumroadTotal.toFixed(2)),
  stripe_delta_pct: Number((stripeDelta * 100).toFixed(2)),
  gumroad_delta_pct: Number((gumroadDelta * 100).toFixed(2)),
  discrepancies,
  reconciled: discrepancies.length === 0
}}];

const input = $input.first().json;
return [{ json: {
  timestamp: new Date().toISOString(),
  workflow: 'W09-daily-revenue-rollup',
  node: $node.name || 'unknown',
  error_message: input.error?.message || JSON.stringify(input).slice(0, 500),
  payload: JSON.stringify(input).slice(0, 500),
  status: 'Open'
}}];
